const b = $json.body || $json;
const clean = (v) => (v ?? '').toString().trim();
const caseIdRaw = clean(b.case_id);
const caseId = /^\d+$/.test(caseIdRaw) ? Number(caseIdRaw) : null;
const phone = clean(b.phone);
const email = clean(b.email);
const canSearchByContact = phone !== '' || email !== '';
const valid = caseId !== null || canSearchByContact;
return [{json:{
  valid,
  error: valid ? '' : 'Debes enviar case_id o (phone/email)',
  case_id: caseId,
  phone,
  email
}}];

const req = $json;
let whereClause = '';
if (req.case_id !== null) {
  whereClause = `c.id = ${req.case_id}`;
} else if (req.email) {
  const email = req.email.replace(/'/g, "''");
  whereClause = `cl.email = '${email}'`;
} else {
  const phone = req.phone.replace(/'/g, "''");
  whereClause = `cl.phone = '${phone}'`;
}
const query = `SELECT
  c.id, c.client_id, c.matter_type, c.status, c.priority, c.summary, c.assigned_lawyer, c.opened_at,
  cl.full_name, cl.email, cl.phone
FROM cases c
JOIN clients cl ON cl.id = c.client_id
WHERE ${whereClause}
ORDER BY c.opened_at DESC
LIMIT 1;`;
return [{json:{...req, query}}];

const rows = $input.all();
if (rows.length === 0) {
  return [{ json: { found: false } }];
}
const c = rows[0].json;
return [{ json: { found: true, ...c } }];

