const c = $('Normalizar Resultado Caso').item.json;
const dlRows = $input.all();
const hasDeadline = dlRows.length > 0;
const deadline = hasDeadline ? dlRows[0].json : null;
return [{json:{
  status:'ok',
  case_id:c.id,
  client_name:c.full_name,
  matter_type:c.matter_type,
  case_status:c.status,
  priority:c.priority,
  assigned_lawyer:c.assigned_lawyer || null,
  summary:c.summary || '',
  next_deadline: deadline ? deadline.due_at : null,
  next_deadline_title: deadline ? deadline.title : null,
  next_action: deadline ? 'preparar_documentos_para_plazo' : 'esperar_actualizacion_abogado'
}}];
